from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about a politician into a readable sentence."""
    if not triples:
        return ""

    # Get the main subject from the first triple
    subject = triples[0].subject

    # Group predicates by type for better sentence structure
    biographical = []
    political = []
    geographic = []
    other = []

    for t in triples:
        if t.predicate in ["birthPlace", "birthDate", "birthYear", "deathPlace", "deathDate", "deathYear"]:
            biographical.append(t)
        elif t.predicate in ["party", "office", "successor", "predecessor", "spouse", "profession", "nationality", "militaryBranch", "militaryRank", "award", "residence", "region"]:
            political.append(t)
        elif t.predicate in ["country", "capital", "largestCity", "state", "language", "officialLanguage", "currency", "leader"]:
            geographic.append(t)
        else:
            other.append(t)

    # Build sentence parts
    parts = []

    # Start with subject and main office/party info
    for t in political:
        if t.predicate == "office":
            parts.append(f"{subject} served as {t.object}")
        elif t.predicate == "party":
            parts.append(f"a member of the {t.object}")
        elif t.predicate == "nationality":
            parts.append(f"of {t.object}")
        elif t.predicate == "profession":
            parts.append(f"a {t.object}")

    # Add birth/death info
    for t in biographical:
        if t.predicate == "birthPlace":
            parts.append(f"who was born in {t.object}")
        elif t.predicate == "birthDate":
            parts.append(f"born on {t.object}")
        elif t.predicate == "birthYear":
            parts.append(f"born in {t.object}")
        elif t.predicate == "deathPlace":
            parts.append(f"who died in {t.object}")
        elif t.predicate == "deathDate":
            parts.append(f"died on {t.object}")
        elif t.predicate == "deathYear":
            parts.append(f"died in {t.object}")

    # Add geographic info
    for t in geographic:
        if t.predicate == "country":
            parts.append(f"from {t.object}")
        elif t.predicate == "capital":
            parts.append(f"with capital {t.object}")

    # Combine into one sentence
    if not parts:
        return subject

    sentence = parts[0]
    for part in parts[1:]:
        sentence += f", {part}"

    return sentence + "."

# EVOLVE-BLOCK-END
